  TextField,
  Stack,
  Alert,
  Snackbar,
  CircularProgress,
  LinearProgress,
  useTheme,
  FormControlLabel,
  Switch,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  FormHelperText,
  Chip
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon,
  Refresh as RefreshIcon
} from '@mui/icons-material';
import { getRules, createRule, updateRule, deleteRule, getNodes, getNodeGroups, getRuleSets, createRuleSet, updateRuleSet, deleteRuleSet, updateRuleSetRules } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Rules = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [rules, setRules] = useState([]);
  const [nodes, setNodes] = useState([]);
  const [nodeGroups, setNodeGroups] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedRule, setSelectedRule] = useState(null);
  const [editRule, setEditRule] = useState({
    name: '',
    type: 'remote',
    url: '',
    rules: [],
    outbound: 'direct',
    nodeGroup: '',
    specificNode: '',
    active: true,
  });
  const [ruleSets, setRuleSets] = useState([]);
  const [openRuleSetDialog, setOpenRuleSetDialog] = useState(false);
  const [editingRuleSet, setEditingRuleSet] = useState(null);

  const outboundTypes = [
    { value: 'direct', label: '直连', description: '不走代理直接连接' },
    { value: 'reject', label: '拒绝', description: '通过DNS拒绝连接' },
    { value: 'node_group', label: '节点组', description: '使用指定节点组' },
    { value: 'specific', label: '指定节点', description: '使用特定节点' },
  ];

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [rulesData, nodesData, groupsData, ruleSetsData] = await Promise.all([
        getRules(),
        getNodes(),
        getNodeGroups(),
        getRuleSets()
      ]);
      setRules(rulesData);
      setNodes(nodesData);
      setNodeGroups(groupsData);
      setRuleSets(ruleSetsData);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.error || '获取数据失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (rule = null) => {
    if (rule) {
      setSelectedRule(rule);
      setEditRule({
        ...rule,
        enabled: rule.enabled ?? true
      });
    } else {
      setSelectedRule(null);
      setEditRule({
        name: '',
        type: 'remote',
        url: '',
        rules: [],
        outbound: 'direct',
        nodeGroup: '',
        specificNode: '',
        active: true,
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedRule(null);
    setEditRule({
      name: '',
      type: 'remote',
      url: '',
      rules: [],
      outbound: 'direct',
      nodeGroup: '',
      specificNode: '',
      active: true,
    });
  };

  const handleSaveRule = async () => {
    try {
      setLoading(true);
      const ruleData = {
        ...editRule,
        rules: editRule.type === 'custom' ? editRule.rules : [],
        url: editRule.type === 'remote' ? editRule.url : '',
      };

      if (selectedRule) {
        await updateRule(selectedRule.id, ruleData);
      } else {
        await createRule(ruleData);
      }
      await fetchData();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError(err.response?.data?.error || '保存规则失败');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteRule(id);
      await fetchData();
      setSuccess(true);
    } catch (err) {
      setError(err.response?.data?.error || '删除规则失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenRuleSetDialog = (ruleSet = null) => {
    setEditingRuleSet(ruleSet);
    setOpenRuleSetDialog(true);
  };

  const handleCloseRuleSetDialog = () => {
    setEditingRuleSet(null);
    setOpenRuleSetDialog(false);
  };

  const handleSaveRuleSet = async (event) => {
    event.preventDefault();
    const formData = new FormData(event.target);
    const data = {
      name: formData.get('name'),
      url: formData.get('url'),
      type: formData.get('type'),
      format: formData.get('format'),
      outbound: formData.get('outbound'),
      description: formData.get('description'),
      enabled: formData.get('enabled') === 'true',
    };

    try {
      setLoading(true);
      if (editingRuleSet) {
        await updateRuleSet(editingRuleSet.id, data);
        setSuccess('规则集更新成功');
      } else {
        await createRuleSet(data);
        setSuccess('规则集创建成功');
      }
      handleCloseRuleSetDialog();
      fetchData();
    } catch (err) {
      setError(err.response?.data?.error || '保存规则集失败');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteRuleSet = async (id) => {
    try {
      setLoading(true);
      await deleteRuleSet(id);
      setSuccess('规则集删除成功');
      fetchData();
    } catch (err) {
      setError(err.response?.data?.error || '删除规则集失败');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateRuleSet = async (id) => {
    try {
      setLoading(true);
      await updateRuleSetRules(id);
      setSuccess('规则集规则更新成功');
      fetchData();
    } catch (err) {
      setError(err.response?.data?.error || '更新规则集规则失败');
    } finally {
      setLoading(false);
    }
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  // 统一规则卡片渲染函数
  const renderRuleCard = (item, type = 'rule') => {
    const isRuleSet = type === 'ruleset';
    const chipLabel = isRuleSet ? item.format : item.type;
    const chipBackground = (theme) => {
      if (isRuleSet) {
        return item.format === 'domain'
          ? 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)'
          : 'linear-gradient(45deg, #42a5f5 30%, #64b5f6 90%)';
      } else {
        return item.type === 'domain'
          ? 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)'
          : item.type === 'ip'
            ? 'linear-gradient(45deg, #42a5f5 30%, #64b5f6 90%)'
            : 'linear-gradient(45deg, #66bb6a 30%, #81c784 90%)';
      }
    };

    // 获取规则来源标签
    const getSourceLabel = () => {
      if (!isRuleSet) {
        return item.type === 'remote' ? '远程规则' : '自定义规则';
      }
      return item.type === 'srs' ? 'SRS规则集' : 'JSON规则集';
    };

    // 获取规则来源标签颜色
    const getSourceChipColor = () => {
      if (!isRuleSet) {
        return item.type === 'remote'
          ? 'linear-gradient(45deg, #ff9800 30%, #ffa726 90%)'  // 橙色渐变
          : 'linear-gradient(45deg, #9c27b0 30%, #ba68c8 90%)'; // 紫色渐变
      }
      return item.type === 'srs'
        ? 'linear-gradient(45deg, #00bcd4 30%, #4dd0e1 90%)'  // 青色渐变
        : 'linear-gradient(45deg, #ff5722 30%, #ff7043 90%)'; // 深橙色渐变
    };

    return (
      <Grid item xs={12} sm={6} md={4} key={item.id}>
        <Card sx={styles.card}>
          <CardContent>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
              <Typography variant="h6" sx={{ fontWeight: 500 }}>
                {item.name}
              </Typography>
              <Stack direction="row" spacing={1}>
                <IconButton
                  size="small"
                  onClick={() => isRuleSet ? handleOpenRuleSetDialog(item) : handleOpenDialog(item)}
                  sx={styles.iconButton}
                >
                  <EditIcon fontSize="small" />
                </IconButton>
                <IconButton
                  size="small"
                  onClick={() => isRuleSet ? handleDeleteRuleSet(item.id) : handleDelete(item.id)}
                  sx={styles.iconButton}
                >
                  <DeleteIcon fontSize="small" />
                </IconButton>
                {isRuleSet && (
                  <IconButton
                    size="small"
                    onClick={() => handleUpdateRuleSet(item.id)}
                    sx={styles.iconButton}
                  >
                    <RefreshIcon fontSize="small" />
                  </IconButton>
                )}
              </Stack>
            </Box>

            <Stack spacing={1}>
              <Box>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {isRuleSet ? '规则集类型' : '匹配规则'}
                </Typography>
                <Typography variant="body1">
                  {isRuleSet 
                    ? (item.type === 'srs' ? 'Sing-box 规则集' : 'JSON 规则集')
                    : item.pattern}
                </Typography>
              </Box>

              <Box>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  {isRuleSet ? '目标出口' : '目标节点'}
                </Typography>
                <Typography variant="body1">
                  {isRuleSet ? item.outbound : item.target}
                </Typography>
              </Box>

              <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
                <Chip 
                  label={chipLabel}
                  size="small"
                  sx={{
                    background: chipBackground,
                    color: '#fff',
                    fontWeight: 500,
                  }}
                />
                <Chip 
                  label={getSourceLabel()}
                  size="small"
                  sx={{
                    background: getSourceChipColor(),
                    color: '#fff',
                    fontWeight: 500,
                  }}
                />
                <Chip 
                  label={item.enabled ? "已启用" : "已禁用"} 
                  size="small"
                  sx={item.enabled ? {
                    ...styles.chip.success,
                    background: 'linear-gradient(45deg, #4caf50 30%, #81c784 90%)',
                    color: '#fff',
                    fontWeight: 500,
                  } : {
                    ...styles.chip.error,
                    background: 'linear-gradient(45deg, #f44336 30%, #e57373 90%)',
                    color: '#fff',
                    fontWeight: 500,
                  }}
                />
              </Stack>

              {isRuleSet && item.description && (
                <Box>
                  <Typography variant="body2" color="text.secondary" gutterBottom>
                    描述
                  </Typography>
                  <Typography variant="body2" sx={{ color: 'text.secondary', fontStyle: 'italic' }}>
                    {item.description}
                  </Typography>
                </Box>
              )}
            </Stack>
          </CardContent>
        </Card>
      </Grid>
    );
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                规则管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={styles.iconButton}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Box sx={{ mb: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h6">规则列表</Typography>
        <Stack direction="row" spacing={1}>
          <Button
            variant="contained"
            size="small"
            startIcon={<AddIcon />}
            onClick={() => handleOpenDialog()}
            sx={styles.actionButton}
          >
            添加规则
          </Button>
          <Button
            variant="contained"
            size="small"
            startIcon={<AddIcon />}
            onClick={() => handleOpenRuleSetDialog()}
            sx={styles.actionButton}
          >
            添加规则集
          </Button>
        </Stack>
      </Box>

      <Grid container spacing={1.5}>
        {rules.map((rule) => renderRuleCard(rule, 'rule'))}
        {ruleSets.map((ruleSet) => renderRuleCard(ruleSet, 'ruleset'))}
      </Grid>

      <Dialog 
        open={openDialog} 
        onClose={handleCloseDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>
          {selectedRule ? '编辑规则' : '添加规则'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="规则名称"
                  value={editRule.name}
                  onChange={(e) => setEditRule({ ...editRule, name: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>

              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>规则类型</InputLabel>
                  <Select
                    value={editRule.type}
                    label="规则类型"
                    onChange={(e) => setEditRule({ ...editRule, type: e.target.value })}
                    sx={styles.textField}
                  >
                    <MenuItem value="remote">远程规则集</MenuItem>
                    <MenuItem value="custom">自定义规则</MenuItem>
                  </Select>
                  <FormHelperText>
                    {editRule.type === 'remote' ? '从URL导入规则集' : '手动添加规则'}
                  </FormHelperText>
                </FormControl>
              </Grid>

              {editRule.type === 'remote' ? (
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="规则集URL"
                    value={editRule.url}
                    onChange={(e) => setEditRule({ ...editRule, url: e.target.value })}
                    size="small"
                    placeholder="https://example.com/rules.txt"
                    sx={styles.textField}
                  />
                </Grid>
              ) : (
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    multiline
                    rows={6}
                    label="规则列表"
                    value={editRule.rules.join('\n')}
                    onChange={(e) => setEditRule({
                      ...editRule,
                      rules: e.target.value.split('\n').filter(r => r.trim())
                    })}
                    size="small"
                    placeholder="每一条规则，例如：
DOMAIN-SUFFIX,google.com
DOMAIN-KEYWORD,google
IP-CIDR,8.8.8.8/32"
                    sx={styles.textField}
                  />
                </Grid>
              )}

              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>出口选择</InputLabel>
                  <Select
                    value={editRule.outbound}
                    label="出口选择"
                    onChange={(e) => setEditRule({ ...editRule, outbound: e.target.value })}
                    sx={styles.textField}
                  >
                    {outboundTypes.map((type) => (
                      <MenuItem key={type.value} value={type.value}>
                        <Stack>
                          <Typography variant="body1">{type.label}</Typography>
                          <Typography variant="caption" color="text.secondary">
                            {type.description}
                          </Typography>
                        </Stack>
                      </MenuItem>
                    ))}
                  </Select>
                </FormControl>
              </Grid>

              {editRule.outbound === 'node_group' && (
                <Grid item xs={12}>
                  <FormControl fullWidth size="small">
                    <InputLabel>节点组</InputLabel>
                    <Select
                      value={editRule.nodeGroup}
                      label="节点组"
                      onChange={(e) => setEditRule({ ...editRule, nodeGroup: e.target.value })}
                      sx={styles.textField}
                    >
                      <MenuItem value="">所有节点组</MenuItem>
                      {nodeGroups.map((group) => (
                        <MenuItem key={group.id} value={group.id}>{group.name}</MenuItem>
                      ))}
                    </Select>
                  </FormControl>
                </Grid>
              )}

              {editRule.outbound === 'specific' && (
                <Grid item xs={12}>
                  <FormControl fullWidth size="small">
                    <InputLabel>指定节点</InputLabel>
                    <Select
                      value={editRule.specificNode}
                      label="指定节点"
                      onChange={(e) => setEditRule({ ...editRule, specificNode: e.target.value })}
                      sx={styles.textField}
                    >
                      {nodes.map((node) => (
                        <MenuItem key={node.id} value={node.id}>{node.name}</MenuItem>
                      ))}
                    </Select>
                  </FormControl>
                </Grid>
              )}

              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={editRule.active}
                      onChange={(e) => setEditRule({ ...editRule, active: e.target.checked })}
                    />
                  }
                  label="启用规则"
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSaveRule}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>

      <Dialog 
        open={openRuleSetDialog} 
        onClose={handleCloseRuleSetDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <form onSubmit={handleSaveRuleSet}>
          <DialogTitle>
            {editingRuleSet ? '编辑规则集' : '添加规则集'}
          </DialogTitle>
          <DialogContent>
            <Box sx={{ pt: 2 }}>
              <Grid container spacing={2}>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="规则集名称"
                    name="name"
                    defaultValue={editingRuleSet?.name}
                    required
                    size="small"
                    sx={styles.textField}
                  />
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="规则集URL"
                    name="url"
                    defaultValue={editingRuleSet?.url}
                    required
                    size="small"
                    placeholder="https://example.com/rules.srs"
                    sx={styles.textField}
                  />
                </Grid>

                <Grid item xs={12}>
                  <FormControl fullWidth size="small">
                    <InputLabel>规则集类型</InputLabel>
                    <Select
                      name="type"
                      defaultValue={editingRuleSet?.type || 'srs'}
                      label="规则集类型"
                      sx={styles.textField}
                    >
                      <MenuItem value="srs">Sing-box 规则集 (.srs)</MenuItem>
                      <MenuItem value="json">JSON 规则集 (.json)</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>

                <Grid item xs={12}>
                  <FormControl fullWidth size="small">
                    <InputLabel>规则格式</InputLabel>
                    <Select
                      name="format"
                      defaultValue={editingRuleSet?.format || 'domain'}
                      label="规则格式"
                      sx={styles.textField}
                    >
                      <MenuItem value="domain">域名规则</MenuItem>
                      <MenuItem value="geoip">IP规则</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>

                <Grid item xs={12}>
                  <FormControl fullWidth size="small">
                    <InputLabel>出口选择</InputLabel>
                    <Select
                      name="outbound"
                      defaultValue={editingRuleSet?.outbound || 'direct'}
                      label="出口选择"
                      sx={styles.textField}
                    >
                      {outboundTypes.map((type) => (
                        <MenuItem key={type.value} value={type.value}>
                          <Stack>
                            <Typography variant="body1">{type.label}</Typography>
                            <Typography variant="caption" color="text.secondary">
                              {type.description}
                            </Typography>
                          </Stack>
                        </MenuItem>
                      ))}
                    </Select>
                  </FormControl>
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="描述"
                    name="description"
                    defaultValue={editingRuleSet?.description}
                    multiline
                    rows={3}
                    size="small"
                    sx={styles.textField}
                  />
                </Grid>

                <Grid item xs={12}>
                  <FormControlLabel
                    control={
                      <Switch
                        name="enabled"
                        defaultChecked={editingRuleSet?.enabled ?? true}
                        value="true"
                      />
                    }
                    label="启用规则集"
                  />
                </Grid>
              </Grid>
            </Box>
          </DialogContent>
          <DialogActions>
            <Button 
              onClick={handleCloseRuleSetDialog}
              size="small"
              sx={{
                color: 'text.secondary',
                '&:hover': {
                  backgroundColor: 'action.hover',
                },
              }}
            >
              取消
            </Button>
            <Button 
              type="submit"
              variant="contained" 
              disabled={loading}
              size="small"
              sx={styles.actionButton}
            >
              保存
            </Button>
          </DialogActions>
        </form>
      </Dialog>
    </Box>
  );
};

export default Rules;
